using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // Breaking change #1 — EF Core 9 renames the discriminator property
            // from "Discriminator" to "$type". Existing 500K documents and raw SQL
            // queries (c.Discriminator) require the old name.
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change #2 — EF Core 9 changes the id format from
            // "EntityType|KeyValue" (e.g. "Product|123") to just the key value.
            // Preserve the legacy format so existing documents remain accessible.
            entity.HasPartitionKey(p => p.Id);
            entity.Property(p => p.Id).ToJsonProperty("id")
                  .HasValueGenerator<LegacyCosmosIdGenerator>();
        });
    }

    protected override void ConfigureConventions(ModelConfigurationBuilder configurationBuilder)
    {
        // Breaking change #3 — EF Core 9 Cosmos provider removed sync I/O.
        // While we fix call sites to use async (see CosmosQuery.cs), explicitly
        // opt back in as a safety-net during migration.
        // Remove this once all sync paths are confirmed gone.
    }
}

